def fibonacci(n):
    if n < 0:
        return 0
    if n <= 1:
        return n
    f, l = 1, 1
    adj = -2  # 2*(-1)^k, starts at -2 since k=1 is odd
    for bit in range(n.bit_length() - 2, -1, -1):
        f = f * l
        l = l * l - adj
        adj = 2
        if (n >> bit) & 1:
            f, l = (f + l) >> 1, (5 * f + l) >> 1
            adj = -2
    return f
